import{_ as e,o as s,c as n,a as o}from"./app.7722c78a.js";const m=JSON.parse('{"title":"依赖预构建","description":"","frontmatter":{"title":"依赖预构建"},"headers":[{"level":2,"title":"原因","slug":"the-why","link":"#the-why","children":[]},{"level":2,"title":"自动依赖搜寻","slug":"automatic-dependency-discovery","link":"#automatic-dependency-discovery","children":[]},{"level":2,"title":"Monorepo 和链接依赖","slug":"monorepos-and-linked-dependencies","link":"#monorepos-and-linked-dependencies","children":[]},{"level":2,"title":"自定义行为","slug":"customizing-the-behavior","link":"#customizing-the-behavior","children":[]},{"level":2,"title":"缓存","slug":"caching","link":"#caching","children":[{"level":3,"title":"文件系统缓存","slug":"file-system-cache","link":"#file-system-cache","children":[]},{"level":3,"title":"浏览器缓存","slug":"browser-cache","link":"#browser-cache","children":[]}]}],"relativePath":"guide/dep-pre-bundling.md"}'),a={name:"guide/dep-pre-bundling.md"},l=o(`<h1 id="dependency-pre-bundling" tabindex="-1">依赖预构建 <a class="header-anchor" href="#dependency-pre-bundling">¶</a></h1><p>当你首次启动 <code>vite</code> 时，你可能会注意到打印出了以下信息：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">Pre-bundling dependencies: （正在预构建依赖：）</span></span>
<span class="line"><span style="color:#A6ACCD;">  react</span></span>
<span class="line"><span style="color:#A6ACCD;">  react-dom</span></span>
<span class="line"><span style="color:#A6ACCD;">(this will be run only when your dependencies or config have changed)（这将只会在你的依赖或配置发生变化时执行）</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><h2 id="the-why" tabindex="-1">原因 <a class="header-anchor" href="#the-why">¶</a></h2><p>这就是 Vite 执行时所做的“依赖预构建”。这个过程有两个目的:</p><ol><li><p><strong>CommonJS 和 UMD 兼容性:</strong> 开发阶段中，Vite 的开发服务器将所有代码视为原生 ES 模块。因此，Vite 必须先将作为 CommonJS 或 UMD 发布的依赖项转换为 ESM。</p><p>当转换 CommonJS 依赖时，Vite 会执行智能导入分析，这样即使导出是动态分配的（如 React），按名导入也会符合预期效果：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;">// 符合预期</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> React</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">useState</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">react</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"></span></code></pre></div></li><li><p><strong>性能：</strong> Vite 将有许多内部模块的 ESM 依赖关系转换为单个模块，以提高后续页面加载性能。</p><p>一些包将它们的 ES 模块构建作为许多单独的文件相互导入。例如，<a href="https://unpkg.com/browse/lodash-es/" target="_blank" rel="noreferrer"><code>lodash-es</code> 有超过 600 个内置模块</a>！当我们执行 <code>import { debounce } from &#39;lodash-es&#39;</code> 时，浏览器同时发出 600 多个 HTTP 请求！尽管服务器在处理这些请求时没有问题，但大量的请求会在浏览器端造成网络拥塞，导致页面的加载速度相当慢。</p><p>通过预构建 <code>lodash-es</code> 成为一个模块，我们就只需要一个 HTTP 请求了！</p></li></ol><div class="tip custom-block"><p class="custom-block-title">注意</p><p>依赖预构建仅会在开发模式下应用，并会使用 <code>esbuild</code> 将依赖转为 ESM 模块。在生产构建中则会使用 <code>@rollup/plugin-commonjs</code>。</p></div><h2 id="automatic-dependency-discovery" tabindex="-1">自动依赖搜寻 <a class="header-anchor" href="#automatic-dependency-discovery">¶</a></h2><p>如果没有找到相应的缓存，Vite 将抓取你的源码，并自动寻找引入的依赖项（即 &quot;bare import&quot;，表示期望从 <code>node_modules</code> 解析），并将这些依赖项作为预构建包的入口点。预构建通过 <code>esbuild</code> 执行，所以它通常非常快。</p><p>在服务器已经启动之后，如果遇到一个新的依赖关系导入，而这个依赖关系还没有在缓存中，Vite 将重新运行依赖构建进程并重新加载页面。</p><h2 id="monorepos-and-linked-dependencies" tabindex="-1">Monorepo 和链接依赖 <a class="header-anchor" href="#monorepos-and-linked-dependencies">¶</a></h2><p>在一个 monorepo 启动中，该仓库中的某个包可能会成为另一个包的依赖。Vite 会自动侦测没有从 <code>node_modules</code> 解析的依赖项，并将链接的依赖视为源码。它不会尝试打包被链接的依赖，而是会分析被链接依赖的依赖列表。</p><p>然而，这需要被链接的依赖被导出为 ESM 格式。如果不是，那么你可以在配置里将此依赖添加到 <a href="/config/dep-optimization-options.html#optimizedeps-include"><code>optimizeDeps.include</code></a> 和 <a href="/config/build-options.html#build-commonjsoptions"><code>build.commonjsOptions.include</code></a> 这两项中。</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">default</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">defineConfig</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">optimizeDeps</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F07178;">include</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">linked-dep</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">]</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">build</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F07178;">commonjsOptions</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">      </span><span style="color:#F07178;">include</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> [</span><span style="color:#89DDFF;">/</span><span style="color:#C3E88D;">linked-dep</span><span style="color:#89DDFF;">/</span><span style="color:#89DDFF;">,</span><span style="color:#C3E88D;"> </span><span style="color:#89DDFF;">/</span><span style="color:#C3E88D;">node_modules</span><span style="color:#89DDFF;">/</span><span style="color:#A6ACCD;">]</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span></code></pre></div><p>当这个被链接的依赖发生变更后，在重启开发服务器时在命令中带上 <code>--force</code> 选项让所有更改生效。</p><div class="warning custom-block"><p class="custom-block-title">重复删除</p><p>由于对链接依赖的解析方式不同，传递性的依赖项可能会不正确地进行重复数据删除，而造成运行时的问题。如果你偶然发现了这个问题，请使用 <code>npm pack</code> 来修复它。</p></div><h2 id="customizing-the-behavior" tabindex="-1">自定义行为 <a class="header-anchor" href="#customizing-the-behavior">¶</a></h2><p>默认的依赖项发现为启发式可能并不总是可取的。在你想要显式地从列表中包含/排除依赖项的情况下, 请使用 <a href="/config/dep-optimization-options.html"><code>optimizeDeps</code> 配置项</a>。</p><p><code>optimizeDeps.include</code> 或 <code>optimizeDeps.exclude</code> 的一个典型使用场景，是当 Vite 在源码中无法直接发现 import 的时候。例如，import 可能是插件转换的结果。这意味着 Vite 无法在初始扫描时发现 import —— 只能在文件被浏览器请求并转换后才能发现。这将导致服务器在启动后立即重新打包。</p><p><code>include</code> 和 <code>exclude</code> 都可以用来处理这个问题。如果依赖项很大（包含很多内部模块）或者是 CommonJS，那么你应该包含它；如果依赖项很小，并且已经是有效的 ESM，则可以排除它，让浏览器直接加载它。</p><h2 id="caching" tabindex="-1">缓存 <a class="header-anchor" href="#caching">¶</a></h2><h3 id="file-system-cache" tabindex="-1">文件系统缓存 <a class="header-anchor" href="#file-system-cache">¶</a></h3><p>Vite 会将预构建的依赖缓存到 <code>node_modules/.vite</code>。它根据几个源来决定是否需要重新运行预构建步骤:</p><ul><li>包管理器的 lockfile 内容，例如 <code>package-lock.json</code>，<code>yarn.lock</code>，<code>pnpm-lock.yaml</code>，或者 <code>bun.lockb</code></li><li>补丁文件夹的修改时间</li><li>可能在 <code>vite.config.js</code> 相关字段中配置过的</li><li><code>NODE_ENV</code> 中的值</li></ul><p>只有在上述其中一项发生更改时，才需要重新运行预构建。</p><p>如果出于某些原因，你想要强制 Vite 重新构建依赖，你可以用 <code>--force</code> 命令行选项启动开发服务器，或者手动删除 <code>node_modules/.vite</code> 目录。</p><h3 id="browser-cache" tabindex="-1">浏览器缓存 <a class="header-anchor" href="#browser-cache">¶</a></h3><p>解析后的依赖请求会以 HTTP 头 <code>max-age=31536000,immutable</code> 强缓存，以提高在开发时的页面重载性能。一旦被缓存，这些请求将永远不会再到达开发服务器。如果安装了不同的版本（这反映在包管理器的 lockfile 中），则附加的版本 query 会自动使它们失效。如果你想通过本地编辑来调试依赖项，你可以:</p><ol><li>通过浏览器调试工具的 Network 选项卡暂时禁用缓存；</li><li>重启 Vite dev server，并添加 <code>--force</code> 命令以重新构建依赖；</li><li>重新载入页面。</li></ol>`,29),p=[l];function c(t,i,d,r,y,D){return s(),n("div",null,p)}const u=e(a,[["render",c]]);export{m as __pageData,u as default};
